import { useState } from "react"
import axios from "axios"

export default function SignupPage({setUser,setPage}){
  const [name,setName] = useState("")
  const [email,setEmail] = useState("")

  const signup = async()=>{
    try{
      const res = await axios.post("http://localhost:5001/user/signup",{name,email})
      setUser(res.data)
      console.log(res.data)
      setPage('chat')
    }catch(e){
      if(e.response?.status===400) alert("User already exists, please login")
      else alert("Signup failed")
    }
  }

  return (
    <div style={{padding:50, background:"#e0f7ff", minHeight:"100vh"}}>
      <h2>Signup</h2>
      <input placeholder="Name" onChange={e=>setName(e.target.value)} />
      <br/><br/>
      <input placeholder="Email" onChange={e=>setEmail(e.target.value)} />
      <br/><br/>
      <button onClick={signup}>Signup</button>
      <p style={{marginTop:10}}>
        Already registered? <span style={{color:"blue",cursor:"pointer"}} onClick={()=>setPage('login')}>Login</span>
      </p>
    </div>
  )
}
